namespace MVZ2.GameContent.IZombie
{
    [IZombieLayoutDefinition(VanillaIZombieLayoutNames.HotRave)]
    public class HotRave : IZombieLayoutDefinition
    {
        public HotRave(string nsp, string name) : base(nsp, name, 5)
        {
            Blueprints = new NamespaceID[]
            {
                VanillaContraptionID.smallDispenser,
                VanillaEnemyID.zombieCloud,
                VanillaEnemyID.popCaptain,
                VanillaBlueprintID.ufoRed,
                VanillaEnemyID.imp,
            };
        }
        public override void Fill(IIZombieMap map, RandomGenerator rng)
        {
            var level = map.Level;

            //SpawnAt(level, 0, 0, VanillaContraptionID.spikeBlock);
            SpawnAt(level, 0, 1, VanillaContraptionID.pistenser);
            SpawnAt(level, 0, 2, VanillaContraptionID.hfpd);
            SpawnAt(level, 0, 2, VanillaContraptionID.stoneShield);
            //SpawnAt(level, 0, 3, VanillaContraptionID.lightningOrb);
            //SpawnAt(level, 0, 4, VanillaContraptionID.stoneDropper);

            SpawnAt(level, 1, 0, VanillaContraptionID.thunderDrum);
            SpawnAt(level, 1, 1, VanillaContraptionID.fireworkDispenser);
            SpawnAt(level, 1, 2, VanillaContraptionID.hfpd);
            SpawnAt(level, 1, 3, VanillaContraptionID.furnace);
            SpawnAt(level, 1, 4, VanillaContraptionID.beacon);

            //SpawnAt(level, 2, 0, VanillaContraptionID.splitenser);
            SpawnAt(level, 2, 1, VanillaContraptionID.diamondSpikes);
            SpawnAt(level, 2, 2, VanillaContraptionID.hellfire);
            SpawnAt(level, 2, 2, VanillaContraptionID.stoneShield);
            //SpawnAt(level, 2, 3, VanillaContraptionID.stoneDropper);
            //SpawnAt(level, 2, 4, VanillaContraptionID.splitenser);

            SpawnAt(level, 3, 0, VanillaContraptionID.mineTNT);
            SpawnAt(level, 3, 1, VanillaContraptionID.furnace);
            SpawnAt(level, 3, 2, VanillaContraptionID.fireworkDispenser);
            SpawnAt(level, 3, 3, VanillaContraptionID.soulFurnace);
            SpawnAt(level, 3, 4, VanillaContraptionID.pistenser);

            //SpawnAt(level, 4, 0, VanillaContraptionID.furnace);
            SpawnAt(level, 4, 1, VanillaContraptionID.furnace);
            SpawnAt(level, 4, 2, VanillaContraptionID.spikeBlock);
            //SpawnAt(level, 4, 3, VanillaContraptionID.spikeBlock);
            SpawnAt(level, 4, 4, VanillaContraptionID.blackHoleBomb);



            //SpawnAt(level, 3, 2, VanillaContraptionID.redline);

            //var rlX = level.GetColumnX(3);       // ÁĐ×ó±ßÔµŁ¬Óë±ę×ĽşěĎßŇ»ÖÂ  
            //var rlZ = level.GetLaneCenterZ(2);   // lane 3 µÄÖĐĐÄ  
            //var rlY = level.GetGroundY(rlX, rlZ);

            //level.Spawn(VanillaContraptionID.redline, new Vector3(rlX, rlY, rlZ), null);

            var buffDef = level.Content.GetBuffDefinition<DebugNoRechargeBuff>();
            if (!level.HasBuff(buffDef))
            {
                level.AddBuff(buffDef);
            }

        }
        private void SpawnAt(LevelEngine level, int column, int lane, NamespaceID entityID)
        {
            var x = level.GetEntityColumnX(column);
            var z = level.GetEntityLaneZ(lane);
            var y = level.GetGroundY(x, z);
            level.Spawn(entityID, new Vector3(x, y, z), null);
        }
    }
}
